package com.hospital.management.controller.admin;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.DepartmentServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/admin/departments")public class DepartmentListServlet extends HttpServlet{private final DepartmentService service;public DepartmentListServlet(){this(new DepartmentServiceImpl());}public DepartmentListServlet(DepartmentService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{PageRequest pr=new PageRequest(num(q.getParameter("page"),1),num(q.getParameter("size"),10),q.getParameter("search"));q.setAttribute("departmentPage",service.listDepartments(pr));q.setAttribute("search",pr.getSearchTerm());q.setAttribute("message",q.getParameter("message"));q.setAttribute("error",q.getParameter("error"));q.getRequestDispatcher("/WEB-INF/views/admin/departments/list.jsp").forward(q,r);}private int num(String v,int d){try{return Integer.parseInt(v);}catch(Exception e){return d;}}}
